import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as l,c as n,f as d,a as e,e as o,b as r,d as s}from"./app-d3648b77.js";const t={},p=e("blockquote",null,[e("p",null,[e("code",null,"clang"),o(" 源码阅读")])],-1),g=s(`<p>对 <code>clang</code> 源码的阅读笔记</p><h1 id="克隆项目" tabindex="-1"><a class="header-anchor" href="#克隆项目" aria-hidden="true">#</a> 克隆项目</h1><p>使用命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">git</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">clone</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">https://github.com/llvm/llvm-project.git</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--depth=1</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>克隆到本地</p><p>不必理会庞大的项目结构，我们通过解耦的方式一步一步来阅读此项目</p><h1 id="导读" tabindex="-1"><a class="header-anchor" href="#导读" aria-hidden="true">#</a> 导读</h1><p>首先我们需要知道 <code>clang</code> 只是编译器的前端部分，负责：</p><ol><li>词法分析</li><li>语法分析</li><li>静态检查</li></ol><p>而 <code>llvm</code> 负责后端的部分</p><blockquote><p>这部分可能随着后续的阅读还会进行修改,先留个坑</p></blockquote><p>我们从前端部分开始阅读，在 <code>clang</code> 文件夹中为其前端部分。</p><blockquote><p>阅读前可能会有一个疑问，为什么 <code>llvm</code> 是用 <code>C++</code> 写的？</p><p>如果你有这个疑问，请 <code>Google</code> 什么是编译器自举</p></blockquote><h1 id="基础" tabindex="-1"><a class="header-anchor" href="#基础" aria-hidden="true">#</a> 基础</h1><h2 id="诊断" tabindex="-1"><a class="header-anchor" href="#诊断" aria-hidden="true">#</a> 诊断</h2><p>不同的<strong>前端阶段</strong>具有不同种类的诊断信息，并且<code>clang</code> 根据问题的严重性对诊断进行了分类，定义在 <code>clang/include/clang/Basic/DiagnosticIDs.h</code> 中，如下图所示</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530214051848.png" alt="image-20230530214051848" tabindex="0" loading="lazy"><figcaption>image-20230530214051848</figcaption></figure><h2 id="llvm-triple" tabindex="-1"><a class="header-anchor" href="#llvm-triple" aria-hidden="true">#</a> <code>llvm::Triple</code></h2><p>此文件的定义不再 <code>clang</code> 文件夹下，请在电脑上安装 <code>clang</code> ，以下以 <code>Manjaro</code> 为例：</p><p>在文件夹 <code>/usr/include/llvm/ADT/Triple.h</code></p><p>其定义的成员变量如下所示：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530214705418.png" alt="image-20230530214705418" tabindex="0" loading="lazy"><figcaption>image-20230530214705418</figcaption></figure><h2 id="llvm-toolchain" tabindex="-1"><a class="header-anchor" href="#llvm-toolchain" aria-hidden="true">#</a> <code>llvm::ToolChain</code></h2><p>在文件夹 <code>/usr/include/clang/Driver/ToolChain.h</code></p><p>这里定义了编译的工具链</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530214745494.png" alt="image-20230530214745494" tabindex="0" loading="lazy"><figcaption>image-20230530214745494</figcaption></figure><h1 id="clang-driver" tabindex="-1"><a class="header-anchor" href="#clang-driver" aria-hidden="true">#</a> clang driver</h1><blockquote><p>可以通过 <code>clang -### xxx.c</code> 来查看 <code>driver</code> 到底调用了哪些命令，例如：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">clang++</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">-###</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">main.cc</span><span style="color:#ABB2BF;"> |&amp; </span><span style="color:#61AFEF;">vi</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">-</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>（由于输出重定向到了 <code>stderr</code> 中，所以这里需要加上<code>&amp;</code> 从jyy老师的课上学到的linux知识）</p><p>在 <code>vim</code> 中，选择最后两行，输入 <code>gqq</code> 即可根据空格拆分，如下图所示：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530221916345.png" alt="image-20230530221916345" tabindex="0" loading="lazy"><figcaption>image-20230530221916345</figcaption></figure></blockquote><h2 id="clang-driver-流程简介" tabindex="-1"><a class="header-anchor" href="#clang-driver-流程简介" aria-hidden="true">#</a> clang driver 流程简介</h2><p><code>clang Driver</code> 负责拼接编译器命令和 <code>ld</code> 命令。</p><blockquote><p>注意：<code>clang driver</code> 自身<strong>不会</strong>对源码进行编译</p></blockquote><p><code>clang Driver</code> 的处理逻辑分为以下几步：</p><p><strong>Parse: Option Parsing</strong>：解析传入的参数</p><p><strong>Pipeline: Compilation Action Construction</strong>：根据每个输入的文件和类型，组建 <code>action</code>（比如 <code>PreprocessJobAction</code>）</p><blockquote><p>可以通过 <code>clang -ccc-print-phases</code> 可以查看需要处理的 <code>action</code>，如下图：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530222151220.png" alt="image-20230530222151220" tabindex="0" loading="lazy"><figcaption>image-20230530222151220</figcaption></figure></blockquote><p><strong>Bind: Tool &amp; Filename Selection</strong>：根据 <code>action</code> 选择对应的<strong>工具</strong>和<strong>文件名</strong>信息</p><blockquote><p>通过 <code>clang -ccc-print-bindings</code> 可以查看对应的<strong>工具</strong>和<strong>文件名</strong>信息，如下图：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530222234455.png" alt="image-20230530222234455" tabindex="0" loading="lazy"><figcaption>image-20230530222234455</figcaption></figure></blockquote><p><strong>Translate: Tool Specific Argument Translation</strong>：根据输入的参数转为不同 <code>tool</code> 的参数</p><blockquote><p>如下图所示：</p><p><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530221916345.png" alt="image-20230530221916345" loading="lazy">其各个工具的参数为：</p><ol><li><code>/usr/bin/clang-15 -cc1</code> 参数： <code>-triple x85_64-pc-linux-gnu</code></li><li><code>/usr/bin/ld</code> 参数： <code>-m elf_x86_64</code></li></ol></blockquote><p><strong>Execute</strong>：调用不同的 <code>tool</code> 执行任务。</p><p>该步骤会通过创建子进程方式调用<code>tool</code></p><p><code>clang driver</code> 最终会创建两个子线程 <code>clang-15 -cc1</code> 和 <code>ld</code> 执行最终的编译任务和链接任务</p><ul><li><code>clang-15 -cc1</code> 可以将源码转为对象文件。本例中，<code>clang-15 -cc1</code> 会将 <code>.cc</code> 文件转为 <code>.o</code> 文件</li></ul><blockquote><p>以下 <code>clang-15</code> 均以 <code>clang</code> 代替</p></blockquote><p><code>clang</code> 的整体流程如下：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530224019240.png" alt="image-20230530224019240" tabindex="0" loading="lazy"><figcaption>image-20230530224019240</figcaption></figure><p>而 <code>clang driver</code> 的功能就是将这些步骤组装起来，</p><p>此流程形式化如下：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230530224449183.png" alt="image-20230530224449183" tabindex="0" loading="lazy"><figcaption>image-20230530224449183</figcaption></figure>`,49),m={href:"https://cloud.tencent.com/developer/article/1803206",target:"_blank",rel:"noopener noreferrer"};function h(u,v){const c=i("ExternalLinkIcon");return l(),n("div",null,[p,d("more"),g,e("blockquote",null,[e("p",null,[o("图片来源于 "),e("a",m,[o("文章"),r(c)])])])])}const y=a(t,[["render",h],["__file","clang-tutorial-0.html.vue"]]);export{y as default};
